## 2. Create test file

**File:** `apps/client/src/layers/features/chat/model/__tests__/classify-transport-error.test.ts`

```typescript
import { describe, it, expect } from 'vitest';
import { classifyTransportError } from '../use-chat-session';
import { TIMING } from '@/layers/shared/lib';

describe('classifyTransportError', () => {
  it('classifies SESSION_LOCKED as locked category, not retryable, with auto-dismiss', () => {
    const err = Object.assign(new Error('Session is locked'), { code: 'SESSION_LOCKED' });
    const result = classifyTransportError(err);

    expect(result).toEqual({
      heading: 'Session in use',
      message: 'Another client is sending a message. Try again in a few seconds.',
      retryable: false,
      autoDismissMs: TIMING.SESSION_BUSY_CLEAR_MS,
    });
  });

  it('classifies TypeError as network error, retryable', () => {
    const err = new TypeError('Failed to fetch');
    const result = classifyTransportError(err);

    expect(result).toEqual({
      heading: 'Connection failed',
      message: 'Could not reach the server. Check your connection and try again.',
      retryable: true,
    });
  });

  it('classifies error with "network" in message as network error', () => {
    const err = new Error('network error');
    const result = classifyTransportError(err);

    expect(result).toEqual({
      heading: 'Connection failed',
      message: 'Could not reach the server. Check your connection and try again.',
      retryable: true,
    });
  });

  it('classifies error with "fetch" in message as network error', () => {
    const err = new Error('fetch failed');
    const result = classifyTransportError(err);

    expect(result).toEqual({
      heading: 'Connection failed',
      message: 'Could not reach the server. Check your connection and try again.',
      retryable: true,
    });
  });

  it('classifies HTTP 500 as server error, retryable', () => {
    const err = Object.assign(new Error('Internal Server Error'), { status: 500 });
    const result = classifyTransportError(err);

    expect(result).toEqual({
      heading: 'Server error',
      message: 'The server encountered an error. Try again.',
      retryable: true,
    });
  });

  it('classifies HTTP 502 as server error, retryable', () => {
    const err = Object.assign(new Error('Bad Gateway'), { status: 502 });
    const result = classifyTransportError(err);

    expect(result).toEqual({
      heading: 'Server error',
      message: 'The server encountered an error. Try again.',
      retryable: true,
    });
  });

  it('classifies HTTP 503 as server error, retryable', () => {
    const err = Object.assign(new Error('Service Unavailable'), { status: 503 });
    const result = classifyTransportError(err);

    expect(result).toEqual({
      heading: 'Server error',
      message: 'The server encountered an error. Try again.',
      retryable: true,
    });
  });

  it('classifies HTTP 408 as timeout, retryable', () => {
    const err = Object.assign(new Error('Request Timeout'), { status: 408 });
    const result = classifyTransportError(err);

    expect(result).toEqual({
      heading: 'Request timed out',
      message: 'The server took too long to respond. Try again.',
      retryable: true,
    });
  });

  it('classifies error with "timeout" in message as timeout, retryable', () => {
    const err = new Error('request timeout exceeded');
    const result = classifyTransportError(err);

    expect(result).toEqual({
      heading: 'Request timed out',
      message: 'The server took too long to respond. Try again.',
      retryable: true,
    });
  });

  it('classifies unknown error as unknown category, not retryable, preserves raw message', () => {
    const err = new Error('Something unexpected happened');
    const result = classifyTransportError(err);

    expect(result).toEqual({
      heading: 'Error',
      message: 'Something unexpected happened',
      retryable: false,
    });
  });

  it('handles non-Error thrown values', () => {
    const result = classifyTransportError('string error');

    expect(result).toEqual({
      heading: 'Error',
      message: 'string error',
      retryable: false,
    });
  });

  it('handles null/undefined thrown values', () => {
    const result = classifyTransportError(null);

    expect(result.heading).toBe('Error');
    expect(result.retryable).toBe(false);
  });

  it('prioritizes SESSION_LOCKED code over message content', () => {
    const err = Object.assign(new Error('network fetch timeout'), { code: 'SESSION_LOCKED' });
    const result = classifyTransportError(err);

    expect(result.heading).toBe('Session in use');
  });
});
```

## Acceptance Criteria

- All 13 test cases pass
- Each error signal (SESSION_LOCKED, TypeError, network keyword, fetch keyword, HTTP 500-599, HTTP 408, timeout keyword, unknown) has at least one test
- Edge cases covered: non-Error values, null, priority ordering
- Test runs successfully: `pnpm vitest run apps/client/src/layers/features/chat/model/__tests__/classify-transport-error.test.ts`

Add component tests verifying the structured error banner renders correctly, shows retry conditionally, and calls handleRetry. These tests should either be added to an existing ChatPanel test or a new focused test file.

