## 1. Create test file

**File:** `apps/client/src/layers/features/chat/ui/__tests__/TransportErrorBanner.test.tsx`

This test needs to mock `useChatSession` to control the `error` value returned. Follow existing test patterns from `ErrorMessageBlock.test.tsx`.

```typescript
/**
 * @vitest-environment jsdom
 */
import { describe, it, expect, vi, afterEach, beforeEach } from 'vitest';
import { render, screen, fireEvent, cleanup } from '@testing-library/react';
import '@testing-library/jest-dom/vitest';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { ChatPanel } from '../ChatPanel';
import { TransportProvider } from '@/layers/shared/model';
import { createMockTransport } from '@dorkos/test-utils';
import type { TransportErrorInfo } from '../../model/chat-types';

// Mock the chat session hook to control error state
const mockSubmitContent = vi.fn();
const mockHandleSubmit = vi.fn();
const mockStop = vi.fn();
const mockSetInput = vi.fn();
const mockMarkToolCallResponded = vi.fn();

let mockError: TransportErrorInfo | null = null;
let mockMessages: Array<{ id: string; role: string; content: string; parts: Array<{ type: string; text: string }>; timestamp: string }> = [];

vi.mock('../../model/use-chat-session', () => ({
  useChatSession: () => ({
    messages: mockMessages,
    input: '',
    setInput: mockSetInput,
    handleSubmit: mockHandleSubmit,
    submitContent: mockSubmitContent,
    status: mockError ? 'error' : 'idle',
    error: mockError,
    sessionBusy: false,
    stop: mockStop,
    isLoadingHistory: false,
    sessionStatus: null,
    streamStartTime: null,
    estimatedTokens: 0,
    isTextStreaming: false,
    isWaitingForUser: false,
    waitingType: null,
    activeInteraction: null,
    markToolCallResponded: mockMarkToolCallResponded,
    isRateLimited: false,
    rateLimitRetryAfter: null,
    systemStatus: null,
  }),
}));

// Mock other hooks used by ChatPanel to avoid side-effects
vi.mock('../../model/use-message-queue', () => ({
  useMessageQueue: () => ({
    queue: [],
    editingIndex: null,
    addToQueue: vi.fn(),
    removeFromQueue: vi.fn(),
    startEditing: vi.fn(),
    saveEditing: vi.fn(),
    cancelEditing: vi.fn(),
  }),
}));

vi.mock('../../model/use-task-state', () => ({
  useTaskState: () => ({
    tasks: [],
    activeForm: null,
    isCollapsed: true,
    toggleCollapse: vi.fn(),
    handleTaskEvent: vi.fn(),
  }),
}));

vi.mock('../../model/use-celebrations', () => ({
  useCelebrations: () => ({
    activeCelebration: null,
    celebratingTaskId: null,
    clearCelebration: vi.fn(),
    handleTaskEvent: vi.fn(),
  }),
}));

vi.mock('../../model/use-tool-shortcuts', () => ({
  useToolShortcuts: () => ({
    handleToolRef: vi.fn(),
    focusedOptionIndex: -1,
  }),
}));

vi.mock('../../model/use-scroll-overlay', () => ({
  useScrollOverlay: () => ({
    isAtBottom: true,
    hasNewMessages: false,
    scrollToBottom: vi.fn(),
    handleScrollStateChange: vi.fn(),
  }),
}));

vi.mock('../../model/use-input-autocomplete', () => ({
  useInputAutocomplete: () => ({
    isOpen: false,
    suggestions: [],
    selectedIndex: 0,
    handleKeyDown: vi.fn(),
    selectSuggestion: vi.fn(),
    dismiss: vi.fn(),
  }),
}));

vi.mock('../../model/use-chat-status-sync', () => ({
  useChatStatusSync: vi.fn(),
}));

vi.mock('../../model/use-file-upload', () => ({
  useFileUpload: () => ({
    pendingFiles: [],
    addFiles: vi.fn(),
    removeFile: vi.fn(),
    clearFiles: vi.fn(),
    isUploading: false,
    hasPendingFiles: false,
    uploadAndGetPaths: vi.fn(),
  }),
}));

vi.mock('@/layers/entities/session', () => ({
  useSessionId: () => [null, vi.fn()],
  useSessionStatus: () => ({ permissionMode: 'default' }),
  useDirectoryState: () => [null],
  insertOptimisticSession: vi.fn(),
}));

vi.mock('@/layers/entities/command', () => ({
  useCommands: () => ({ data: { commands: [] } }),
}));

vi.mock('@/layers/features/files', () => ({
  useFiles: () => ({ data: { files: [] } }),
}));

vi.mock('@/layers/shared/model', async () => {
  const actual = await vi.importActual('@/layers/shared/model');
  return {
    ...actual,
    useAppStore: () => false,
    useTransport: () => createMockTransport(),
  };
});

vi.mock('@/layers/shared/lib', async () => {
  const actual = await vi.importActual('@/layers/shared/lib');
  return {
    ...actual,
    playNotificationSound: vi.fn(),
  };
});

const queryClient = new QueryClient({
  defaultOptions: { queries: { retry: false } },
});

function Wrapper({ children }: { children: React.ReactNode }) {
  return (
    <QueryClientProvider client={queryClient}>
      {children}
    </QueryClientProvider>
  );
}

describe('TransportErrorBanner', () => {
  beforeEach(() => {
    mockError = null;
    mockMessages = [];
    vi.clearAllMocks();
  });

  afterEach(cleanup);

  it('does not render banner when error is null', () => {
    render(<ChatPanel sessionId="test" />, { wrapper: Wrapper });

    expect(screen.queryByText('Connection failed')).not.toBeInTheDocument();
    expect(screen.queryByText('Server error')).not.toBeInTheDocument();
  });

  it('renders heading and message for network error', () => {
    mockError = {
      heading: 'Connection failed',
      message: 'Could not reach the server. Check your connection and try again.',
      retryable: true,
    };

    render(<ChatPanel sessionId="test" />, { wrapper: Wrapper });

    expect(screen.getByText('Connection failed')).toBeInTheDocument();
    expect(screen.getByText('Could not reach the server. Check your connection and try again.')).toBeInTheDocument();
  });

  it('renders heading and message for server error', () => {
    mockError = {
      heading: 'Server error',
      message: 'The server encountered an error. Try again.',
      retryable: true,
    };

    render(<ChatPanel sessionId="test" />, { wrapper: Wrapper });

    expect(screen.getByText('Server error')).toBeInTheDocument();
    expect(screen.getByText('The server encountered an error. Try again.')).toBeInTheDocument();
  });

  it('shows retry button when error is retryable', () => {
    mockError = {
      heading: 'Connection failed',
      message: 'Could not reach the server.',
      retryable: true,
    };

    render(<ChatPanel sessionId="test" />, { wrapper: Wrapper });

    expect(screen.getByRole('button', { name: /retry/i })).toBeInTheDocument();
  });

  it('does not show retry button when error is not retryable', () => {
    mockError = {
      heading: 'Error',
      message: 'Something went wrong',
      retryable: false,
    };

    render(<ChatPanel sessionId="test" />, { wrapper: Wrapper });

    expect(screen.queryByRole('button', { name: /retry/i })).not.toBeInTheDocument();
  });

  it('calls handleRetry when retry button is clicked', () => {
    mockMessages = [
      {
        id: 'msg-1',
        role: 'user',
        content: 'Hello',
        parts: [{ type: 'text', text: 'Hello' }],
        timestamp: new Date().toISOString(),
      },
    ];
    mockError = {
      heading: 'Server error',
      message: 'The server encountered an error.',
      retryable: true,
    };

    render(<ChatPanel sessionId="test" />, { wrapper: Wrapper });

    fireEvent.click(screen.getByRole('button', { name: /retry/i }));
    expect(mockSubmitContent).toHaveBeenCalledWith('Hello');
  });

  it('renders session locked error with correct heading', () => {
    mockError = {
      heading: 'Session in use',
      message: 'Another client is sending a message. Try again in a few seconds.',
      retryable: false,
      autoDismissMs: 5000,
    };

    render(<ChatPanel sessionId="test" />, { wrapper: Wrapper });

    expect(screen.getByText('Session in use')).toBeInTheDocument();
    expect(screen.queryByRole('button', { name: /retry/i })).not.toBeInTheDocument();
  });
});
```

Note: The exact mock structure may need adjustment based on how ChatPanel imports its dependencies. The key patterns follow existing tests in the `__tests__/` directory (e.g., `ErrorMessageBlock.test.tsx`). If ChatPanel is too complex to render fully in isolation, an alternative approach is to extract the banner into a small `TransportErrorBanner` component in the same file and test that directly.

## Acceptance Criteria

- 7 test cases covering: no error, network error display, server error display, retry button conditional visibility, retry click behavior, session locked display
- Tests pass: `pnpm vitest run apps/client/src/layers/features/chat/ui/__tests__/TransportErrorBanner.test.tsx`
- Tests follow project conventions: `@vitest-environment jsdom`, cleanup in afterEach, `@testing-library/jest-dom/vitest`
